import { useEffect, useState } from 'react';
import { supabase } from '../supabase';
import { ROLE_LABELS } from '../supabase';
import { Badge, Btn, GhostBtn, Modal, Field, Empty, PageHeader, inputStyle, selectStyle, useToast, Toast, Icon } from './ui';
import { LoadingPage } from './Dashboard';

const ROLE_COLORS = {
  admin:'#f97316', office_manager:'#3b82f6', foreman:'#22c55e', field_crew:'#8b5cf6',
};

export default function Users() {
  const [users, setUsers]     = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId]   = useState(null);
  const { toast, show } = useToast();
  const blank = { email:'', full_name:'', role:'field_crew', password:'' };
  const [form, setForm] = useState(blank);

  useEffect(()=>{ load(); },[]);

  const load = async () => {
    const { data } = await supabase.from('profiles').select('*').order('full_name');
    setUsers(data||[]);
    setLoading(false);
  };

  const openNew  = () => { setForm(blank); setEditId(null); setShowForm(true); };
  const openEdit = (u) => { setForm({...u, password:''}); setEditId(u.id); setShowForm(true); };

  const save = async () => {
    if (!form.email||!form.full_name) return show('Email and name required','error');
    if (editId) {
      // Update profile role/name
      const { error } = await supabase.from('profiles').update({ full_name:form.full_name, role:form.role }).eq('id',editId);
      if (error) return show(error.message,'error');
      show('User updated');
    } else {
      if (!form.password||form.password.length<8) return show('Password must be at least 8 characters','error');
      // Create user via Supabase Admin API — requires service role key in production
      // For now we use the standard signup flow
      const { data, error } = await supabase.auth.signUp({
        email: form.email,
        password: form.password,
        options: { data: { full_name: form.full_name, role: form.role } },
      });
      if (error) return show(error.message,'error');
      show('User created — they will receive a confirmation email');
    }
    setShowForm(false);
    load();
  };

  const updateRole = async (id, role) => {
    await supabase.from('profiles').update({ role }).eq('id', id);
    show('Role updated');
    load();
  };

  if (loading) return <LoadingPage/>;

  const f = (k) => ({ value:form[k], onChange:e=>setForm(p=>({...p,[k]:e.target.value})) });

  return (
    <div style={{padding:32}}>
      <PageHeader title="User Management" subtitle={`${users.length} team members`}
        action={<Btn icon="plus" onClick={openNew}>Add User</Btn>}/>

      {/* Role legend */}
      <div style={{background:'#0f1218',border:'1px solid #1e2530',borderRadius:10,padding:'14px 20px',marginBottom:24}}>
        <div style={{fontSize:11,fontWeight:600,letterSpacing:2,textTransform:'uppercase',color:'#475569',marginBottom:12}}>Role Permissions</div>
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))',gap:12}}>
          {[
            ['admin','Full system access — all modules'],
            ['office_manager','Dashboard, invoices, history, costs, damage reports'],
            ['foreman','Dashboard, log maintenance, damage, history, PM schedules'],
            ['field_crew','Log maintenance + submit damage reports only'],
          ].map(([role,desc])=>(
            <div key={role} style={{display:'flex',gap:8,alignItems:'flex-start'}}>
              <Badge text={ROLE_LABELS[role]} color={ROLE_COLORS[role]}/>
              <span style={{fontSize:12,color:'#64748b'}}>{desc}</span>
            </div>
          ))}
        </div>
      </div>

      <div style={{background:'#0f1218',borderRadius:12,border:'1px solid #1e2530',overflow:'hidden'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:13.5}}>
          <thead>
            <tr style={{borderBottom:'1px solid #1e2530'}}>
              {['Name','Email','Role','Actions'].map(h=>(
                <th key={h} style={{padding:'12px 16px',textAlign:'left',fontSize:11,fontWeight:600,letterSpacing:1.5,textTransform:'uppercase',color:'#475569'}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {users.length===0 && <tr><td colSpan={4} style={{padding:32,textAlign:'center',color:'#475569'}}>No users found</td></tr>}
            {users.map(u=>(
              <tr key={u.id} style={{borderBottom:'1px solid #1e2530'}}
                onMouseEnter={e=>e.currentTarget.style.background='#111827'}
                onMouseLeave={e=>e.currentTarget.style.background='transparent'}
              >
                <td style={{padding:'12px 16px',fontWeight:500}}>{u.full_name||'—'}</td>
                <td style={{padding:'12px 16px',color:'#94a3b8',fontSize:13}}>{u.email}</td>
                <td style={{padding:'12px 16px'}}>
                  <select
                    value={u.role}
                    onChange={e=>updateRole(u.id,e.target.value)}
                    style={{...selectStyle,width:'auto',padding:'5px 10px',fontSize:12}}
                  >
                    {Object.entries(ROLE_LABELS).map(([v,l])=><option key={v} value={v}>{l}</option>)}
                  </select>
                </td>
                <td style={{padding:'12px 16px'}}>
                  <div style={{display:'flex',gap:6}}>
                    <button onClick={()=>openEdit(u)} title="Edit name" style={{background:'transparent',border:'1px solid #1e2530',borderRadius:6,cursor:'pointer',color:'#64748b',padding:'6px 10px',fontSize:12,fontFamily:'inherit'}}
                    onMouseEnter={e=>{e.currentTarget.style.background='#1e2530';e.currentTarget.style.color='#e2e8f0';}}
                    onMouseLeave={e=>{e.currentTarget.style.background='transparent';e.currentTarget.style.color='#64748b';}}
                    >Edit</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && (
        <Modal title={editId?'Edit User':'Add New User'} onClose={()=>setShowForm(false)}>
          {!editId && (
            <div style={{background:'#1e2530',borderRadius:8,padding:'10px 14px',fontSize:12,color:'#64748b',marginBottom:16}}>
              💡 The new user will receive an email to confirm their account before they can sign in.
            </div>
          )}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>
            <Field label="Full Name *"><input style={inputStyle} {...f('full_name')} placeholder="Jane Smith"/></Field>
            <Field label="Role">
              <select style={selectStyle} {...f('role')}>
                {Object.entries(ROLE_LABELS).map(([v,l])=><option key={v} value={v}>{l}</option>)}
              </select>
            </Field>
            {!editId && <>
              <Field label="Email *"><input type="email" style={inputStyle} {...f('email')} placeholder="jane@company.com"/></Field>
              <Field label="Temporary Password *"><input type="password" style={inputStyle} {...f('password')} placeholder="Min 8 characters"/></Field>
            </>}
          </div>
          <div style={{display:'flex',justifyContent:'flex-end',gap:10,marginTop:20}}>
            <GhostBtn onClick={()=>setShowForm(false)}>Cancel</GhostBtn>
            <Btn onClick={save}>{editId?'Save Changes':'Create User'}</Btn>
          </div>
        </Modal>
      )}
      <Toast toast={toast}/>
    </div>
  );
}
